// Frogger - Player controlled frog
const GRID_SIZE = 20;
const MAX_X = 380;
const MIN_X = -380;
const GOAL_Y = 250;
const WATER_TOP_Y = 100;
const WATER_BOTTOM_Y = 200;

// Initialize state on first run
if (!state.frogger) {
  state.frogger = {
    lives: 3,
    level: 1,
    maxYReached: -250,
    score: 0,
    dead: false,
    onLog: false
  };
}

const froggerState = state.frogger;

// Check if dead
if (froggerState.dead) {
  return;
}

const oldX = self.x;
const oldY = self.y;

// Input handling - move one grid cell
if (Input.isKeyPressed('KeyW')) {
  self.y -= GRID_SIZE;
}
if (Input.isKeyPressed('KeyS')) {
  self.y += GRID_SIZE;
}
if (Input.isKeyPressed('KeyA')) {
  self.x -= GRID_SIZE;
}
if (Input.isKeyPressed('KeyD')) {
  self.x += GRID_SIZE;
}

// Clamp X to bounds
if (self.x > MAX_X) self.x = MAX_X;
if (self.x < MIN_X) self.x = MIN_X;

// Track max Y reached for scoring
if (self.y > froggerState.maxYReached) {
  froggerState.maxYReached = self.y;
  froggerState.score = Math.max(0, froggerState.maxYReached + 250) * 10;
}

// Check collision with cars (road area: y -180 to -20)
if (self.y >= -180 && self.y <= -20) {
  const cars = entities.list().filter(name => name.includes('Car'));
  for (let carName of cars) {
    const car = entities.get(carName);
    if (car && aabbCollision(self, car)) {
      loseLives(1);
      resetPosition();
      return;
    }
  }
}

// Check if in river (water area: y 100 to 200)
if (self.y >= 100 && self.y <= 200) {
  // Must be standing on a log
  const logs = entities.list().filter(name => name.includes('Log'));
  froggerState.onLog = false;

  for (let logName of logs) {
    const log = entities.get(logName);
    if (log && aabbCollision(self, log)) {
      froggerState.onLog = true;
      // Move with the log
      const logSpeed = logName.includes('Lane 1') ? -1.5 : 
                       logName.includes('Lane 2') ? 2 :
                       -1; // Lane 3
      self.x += logSpeed * dt;
      break;
    }
  }

  // If not on a log, die from water
  if (!froggerState.onLog) {
    loseLives(1);
    resetPosition();
    return;
  }
}

// Check if reached goal
if (self.y >= GOAL_Y) {
  froggerState.level += 1;
  froggerState.score += 100;
  resetPosition();
  return;
}

// Helper function for AABB collision
function aabbCollision(obj1, obj2) {
  const w1 = obj1.width || 20;
  const h1 = obj1.height || 20;
  const w2 = obj2.width || 40;
  const h2 = obj2.height || 15;

  return obj1.x < obj2.x + w2 &&
         obj1.x + w1 > obj2.x &&
         obj1.y < obj2.y + h2 &&
         obj1.y + h1 > obj2.y;
}

function loseLives(count) {
  froggerState.lives -= count;
  if (froggerState.lives <= 0) {
    froggerState.dead = true;
  }
}

function resetPosition() {
  self.x = 0;
  self.y = -250;
}

// Car Lane 1 - Manager for cars moving right
const LANE_Y = -180;
const SPEED = 3;
const CAR_WIDTH = 40;
const SPAWN_X = -400;
const DESPAWN_X = 420;

// Initialize car pool
if (!state.carLane1) {
  state.carLane1 = {
    cars: [],
    spawnTimer: 0
  };
}

const laneState = state.carLane1;

// Spawn cars periodically
laneState.spawnTimer += dt;
if (laneState.spawnTimer > 1.5) {
  laneState.spawnTimer = 0;
  let car = {
    x: SPAWN_X,
    y: LANE_Y,
    width: CAR_WIDTH,
    height: 15,
    speed: SPEED,
    direction: 1 // right
  };
  laneState.cars.push(car);
}

// Update existing cars
for (let i = 0; i < laneState.cars.length; i++) {
  const car = laneState.cars[i];
  car.x += car.speed * car.direction * dt;

  // Remove if off screen
  if (car.x > DESPAWN_X) {
    laneState.cars.splice(i, 1);
    i--;
  }
}

// Update visual position for this manager sprite
if (laneState.cars.length > 0) {
  const firstCar = laneState.cars[0];
  self.x = firstCar.x;
  self.y = firstCar.y;
}

