  state.logLane1 = {
    logs: [],
    spawnTimer: 0
  };
}

const laneState = state.logLane1;

// Spawn logs periodically
laneState.spawnTimer += dt;
if (laneState.spawnTimer > 2) {
  laneState.spawnTimer = 0;
  let log = {
    x: SPAWN_X,
    y: LANE_Y,
    width: LOG_WIDTH,
    height: 15,
    speed: SPEED,
    direction: -1 // left
  };
  laneState.logs.push(log);
}

// Update existing logs
for (let i = 0; i < laneState.logs.length; i++) {
  const log = laneState.logs[i];
  log.x += log.speed * log.direction * dt;

  // Remove if off screen
  if (log.x < DESPAWN_X) {
    laneState.logs.splice(i, 1);
    i--;
  }
}

// Update visual position for this manager sprite
if (laneState.logs.length > 0) {
  const firstLog = laneState.logs[0];
  self.x = firstLog.x;
  self.y = firstLog.y;
}

